
.calendar,
.calendar * {
  box-sizing: border-box;
}
.calendar {
  background-color: #fff;
  padding: 7px;
  text-align: center;
}
.calendar .calendar-header {
  min-width: 100%;
  padding: 10px;
  font-size: 18px;
  color: #555;
}
.calendar .calendar-header a {
  margin: 0;
  padding: 4px;
  color: #555;
  text-decoration: none;
  outline: none;
}
.calendar .calendar-header a:hover,
.calendar .calendar-header a:active {
  outline: none;
  text-decoration: none;
  color: #20a0ff;
}
.calendar .calendar-header a:focus {
  color: #555;
}
.calendar .calendar-header .calendar-nav .calendar-nav-prev {
  float: left;
}
.calendar .calendar-header .calendar-nav .calendar-nav-next {
  float: right;
}
.calendar .calendar-header .calendar-nav a {
  display: inline-block;
  width: auto;
  height: 30px;
  padding: 5px;
  line-height: normal;
}
.calendar .calendar-header .calendar-nav .calendar-title {
  margin: 0 60px;
}
.calendar .calendar-body {
  width: 100%;
}
.calendar .calendar-body thead th {
  padding: 10px;
  font-weight: 400;
  font-size: 20px;
  color: #555;
}
.calendar .calendar-body tbody {
/*border 1px solid #ddd*/
  height: 80%;
  position: absolute;
}
.calendar .calendar-body tbody td {
  height: 140px !important;
  padding: 10px;
  text-align: center;
  cursor: pointer;
  font-size: 20px;
  position: relative;
  border-radius: 5px;
}
.calendar .calendar-body tbody td.this-month {
  color: #555;
  background: #edeff0;
}
.calendar .calendar-body tbody td.this-month:hover {
  background-color: #dedede;
  color: #20a0ff;
}
.calendar .calendar-body tbody td.this-month.today {
  background-color: #99f;
  color: #fff;
}
.calendar .calendar-body tbody td.last-month,
.calendar .calendar-body tbody td.next-month {
  color: #8b8b8b;
}
.calendar .calendar-body tbody td .date .task {
  display: block;
/*color #f00*/
  position: absolute;
  right: 0;
  top: 0;
}
.calendar .calendar-body tbody .calendar-years td,
.calendar .calendar-body tbody .calendar-months td {
  color: #555;
}
.calendar .calendar-body tbody .calendar-years td:hover,
.calendar .calendar-body tbody .calendar-months td:hover {
  background-color: #f4f4ff;
  color: #20a0ff;
}
/*滚动条样式*/
.tw-scrollable-layout {
  overflow-y: auto;
  overflow-x: hidden;
  -webkit-overflow-scrolling: touch;
}
.tw-scrollable-layout::-webkit-scrollbar {
  background: transparent;
  width: 8px;
  height: 8px;
}
.tw-scrollable-layout::-webkit-scrollbar-track {
  background: #f3f4f5;
  width: 8px;
  height: 8px;
  border-radius: 4px;
}
.tw-scrollable-layout::-webkit-scrollbar-thumb {
  background: #b0b4bb;
  width: 8px;
  height: 8px;
  border-radius: 4px;
}
.tw-scrollable-layout::-webkit-scrollbar-thumb:hover {
  background: #c1c4cb;
}
.tw-scrollable-layout.--only-show-scrollbar-while-hover:not(:hover)::-webkit-scrollbar-track,
.tw-scrollable-layout.--only-show-scrollbar-while-hover:not(:hover)::-webkit-scrollbar-thumb,
.tw-scrollable-layout.--only-show-scrollbar-while-hover:not(:hover)::-webkit-scrollbar-thumb:hover {
  background: none;
}
.tw-scrollable-layout.--parallax {
  -webkit-perspective: 1px;
  perspective: 1px;
}


